import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import CustomerModal from './components/CustomerModal';
// Import other components as they become ready
 import CreatePricingForm from './components/pricing/CreatePricingForm';
// import InventoryPage from './components/InventoryPage';
// import BillingPage from './components/BillingPage';

function App() {
  return (
    <Router>
      <div className="App">
        <header className="App-header">
          <h1>Welcome to Our Billing Application</h1>
          <nav>
            <ul>
              <li><Link to="/customer">Customer</Link></li>
              <li><Link to="/pricing">Pricing</Link></li>
              <li><Link to="/inventory">Inventory</Link></li>
              <li><Link to="/billing">Billing</Link></li>
            </ul>
          </nav>
        </header>
        <Routes>
          <Route path="/customer" element={<CustomerModal />} />
          {/* Uncomment and update the following lines as the respective components are ready */}
          <Route path="/pricing" element={<CreatePricingForm />} />
          {/* <Route path="/inventory" element={<InventoryPage />} />
          <Route path="/billing" element={<BillingPage />} /> */}
          {/* Placeholder routes until components are ready */}
          <Route path="/pricing" element={<div>Pricing Component Here</div>} />
          <Route path="/inventory" element={<div>Inventory Component Here</div>} />
          <Route path="/billing" element={<div>Billing Component Here</div>} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
